#include <stdio.h>
int main() {
    int T, N, M, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int a[N], l[M], r[M];
        for (int i = 0; i < N; i++) scanf("%d", &a[i]);
        for (int i = 0; i < M; i++) scanf("%d %d", &l[i], &r[i]);
        scanf("%d", &K);
        int x[K];
        for (int i = 0; i < K; i++) scanf("%d", &x[i]);
        int prefix_sum[N];
        prefix_sum[0] = a[0];
        for (int i = 1; i < N; i++) prefix_sum[i] = prefix_sum[i-1] + a[i];
        for (int i = 0; i < K; i++) {
            int ans = 0;
            for (int j = 0; j < M; j++) {
                int bursted = prefix_sum[r[j]-1] - (l[j] > 1 ? prefix_sum[l[j]-2] : 0);
                if (bursted == 0) ans++;
            }
            printf("%d\n", ans);
            a[x[i]-1]--;
            for (int j = x[i]-1; j < N; j++) prefix_sum[j]--;
        }
    }
    return 0;
}

