                l[i] = sc.nextInt();
                r[i] = sc.nextInt();
            }
            int K = sc.nextInt();
            int[] x = new int[K];
            for (int i = 0; i < K; i++) x[i] = sc.nextInt();
            int[] prefix_sum = new int[N];
            prefix_sum[0] = a[0];
            for (int i = 1; i < N; i++) prefix_sum[i] = prefix_sum[i-1] + a[i];
            for (int i = 0; i < K; i++) {
                int ans = 0;
                for (int j = 0; j < M; j++) {
                    int bursted = prefix_sum[r[j]-1] - (l[j] > 1 ? prefix_sum[l[j]-2] : 0);
